import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"灯具","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/生活/灯具.md","filePath":"ccc/生活/灯具.md"}`),a={name:`ccc/生活/灯具.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="灯具" tabindex="-1">灯具 <a class="header-anchor" href="#灯具" aria-label="Permalink to “灯具”">​</a></h1><h2 id="台灯" tabindex="-1">台灯 <a class="header-anchor" href="#台灯" aria-label="Permalink to “台灯”">​</a></h2><p>现在技术相当成熟，Ra90以上的LED灯满天飞。</p><h3 id="警惕荧光粉老化" tabindex="-1">警惕荧光粉老化 <a class="header-anchor" href="#警惕荧光粉老化" aria-label="Permalink to “警惕荧光粉老化”">​</a></h3><p>目前的高显色指数的LED灯泡主要是蓝光或紫光激发荧光粉，单芯片蓝光激发会有明显的蓝光波峰。双蓝光芯片，用两种波长波峰不同的蓝光LED激发，光谱图上蓝光部分会有两个小波峰。还有一种紫光激发荧光粉。</p><p>尽管这些灯泡大吹特吹如何护眼，显色指数也很高，然而一旦荧光粉老化，蓝光，紫光会直接泄露。相对被妖魔化的蓝光，紫光危害反而更大。</p><p>温度是荧光粉寿命的一大杀手，<strong>金属外壳的灯泡加强散热</strong>可能可以延长寿命。现在有很多廉价的高显指灯泡，全新的光谱还可以，但是往往用塑料外壳。</p><p>要求高，工作5000小时左右就开始老化。10000小时之后基本就能测到蓝光或紫光的波峰了。</p><blockquote><p>如果很怕蓝光，紫光，可以网上买个显示器的防蓝光膜贴在灯上，基本都是uv400近乎完全阻隔，410~450nm波长阻隔率50%左右。</p></blockquote><p>LED灯珠有非常严重的热疲劳失效。用过2年的LED灯，拆开来看看，往往焊点成渣，灯珠本身往往也有严重的热疲劳，热风一吹，烙铁一碰就成酥了。</p><p><strong>所以用LED灯希望护眼的重中之重是每隔1~2年就换新，没坏也换。</strong></p><h3 id="台灯具体推荐" tabindex="-1">台灯具体推荐 <a class="header-anchor" href="#台灯具体推荐" aria-label="Permalink to “台灯具体推荐”">​</a></h3><p>台灯入门级推荐买E27接口的台灯，易于维护，成本低。主要缺点是均匀度一般，照射范围小，影子重。最好用闪光灯用的柔光罩罩住防炫光。</p><p>圆饼状的LED台灯（达伦，京东京造等），相对e27台灯，照射范围大一些，纸张反射炫光稍好一点，均匀度好一点。但是影子重没有明显改善。</p><p>长条状的如小米桌面台灯pro读写版，主要提升在照射范围，但是减影和均匀度还是差些。</p><p>米家桌面学习灯PRO，要放在人正前方才能完全发挥，主要提升就是改善影子和均匀度，照射范围也更大。</p><p><strong>台灯基本是10分价钱1分提升，主要提升痒点，一个人用我认为e27台灯便宜实惠，要么米家桌面学习灯PRO，改善了大部分痒点。</strong></p><p>大路灯除了贵，对于大部分人的伏案照明算是比较理想的方案，眩光，光照范围、均匀度相对台灯都可以一力降十会，可以看看undersky品牌。</p><h3 id="e27台灯搭配的灯泡" tabindex="-1">E27台灯搭配的灯泡 <a class="header-anchor" href="#e27台灯搭配的灯泡" aria-label="Permalink to “E27台灯搭配的灯泡”">​</a></h3><ul><li>灯好多旗舰店，荣旗。</li></ul><p><a href="https://s.click.taobao.com/3L0Ukrt?af=3&amp;union_lens=lensId%3APUB%401713117039%402127d135_0d21_18eddbb89e4_162b%40027QgosPgFlRdZQ7LhR1yCkx%40eyJmbG9vcklkIjo4MDY3NCwiic3BtQiiI6Il9wb3J0YWxfdjJfcGFnZXNfcHJvbW9fZ29vZHNfaW5kZXhfaHRtIiiwiic3JjRmxvb3JJZCI6IjgwNjc0In0ie" target="_blank" rel="noreferrer">金属壳高显色灯泡</a>，双蓝光LED。</p><p>灯好多的产品看拆解，电路用料，外壳用料，性价比不错。</p><ul><li>魅族Lipro，sunlike光珠，紫光激发。</li></ul><p>零售产品中，各方面都算是T1梯队。</p><ul><li><p>闪普，查工商信息是恒大光电。sku和闪浦一样，不清楚是什么关系。</p><ul><li>他们高大上的型号，卖100多块，光谱连续性确实很好，然并卵。紫光激发，红光有俩波峰，可能是掺了两种不同的红光荧光粉。性价比太低，我认为没有意义。</li></ul></li><li><p>Blink可以通过快速开关调节亮度，还是单芯片蓝光激发，注意好像会发好几年前的库存，老旧库存荧光粉可能老化。</p></li></ul><p>福珠存在大量数据造假，虚标参数的行为。</p><p>淘宝·光美科技，可以diy定制。</p><p>淘宝·微工高显色照明。</p><p>这些标榜发骚级的产品，在我看来根本不发骚。真发骚应该是红绿蓝三种LED组合混合成白光，但是因为三种LED的光衰不一样，所以产品可能不好做吧。</p><h3 id="卤素灯" tabindex="-1">卤素灯 <a class="header-anchor" href="#卤素灯" aria-label="Permalink to “卤素灯”">​</a></h3><p>卤素灯虽然蓝光能量较小。但是红外能量却异常的高，红外能量和白内障正相关，同时也可能是潜在的皮肤伤害源。光谱连续性较差，存在跳跃波动，但是单纯看显色性这个指标还是可以的。主要缺点还有色温较低发黄。</p><p>如果不改直流电源，是50hz的低频频闪。不过现在卖家基本都有直流电源搭着卖，不用DIY直流电源了。</p><p>非要买卤素灯，尽量买本来就是卤素灯的灯架，比如朗德万斯（欧司朗拆分）柏林。因为发热很大，廉价LED灯架受热会不会逸出有害物质也不好说。</p><h3 id="荧光灯搭配电子镇流器" tabindex="-1">荧光灯搭配电子镇流器 <a class="header-anchor" href="#荧光灯搭配电子镇流器" aria-label="Permalink to “荧光灯搭配电子镇流器”">​</a></h3><p>荧光灯搭配电子镇流器，是高频频闪还算凑合。但是很不环保，我是觉得没必要再折腾这玩意了。</p><p>非要用荧光灯正常情况下就直接有uva泄露，灯管玻璃通常不能完全阻隔uva。作为台灯，距离太近。有兴趣可以网上买个显示器的防蓝光膜，基本都是uv400近乎完全阻隔，410~450nm波长蓝光阻隔率50%左右。</p><h3 id="无可视频闪就够了" tabindex="-1">无可视频闪就够了 <a class="header-anchor" href="#无可视频闪就够了" aria-label="Permalink to “无可视频闪就够了”">​</a></h3><p>所有的灯吹嘘无频闪基本都是手机拍不出频闪，肉眼无法察觉频闪，用仪器测还是有频闪，但只要符合国标就足够。</p><p>LED本来就是直流驱动，引起频闪的主要是AC转DC过程中产生的纹波以及调光方式，高频pwm调光相对所谓横流调光，反而频闪的比例有可能更低。</p>`,39)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};